			// 统计接口1
			chartDialog1() {
				this.$nextTick(()=>{
					var pingjiajieguoChart1 = echarts.init(document.getElementById("pingjiajieguoChart1"),'macarons');
					let params = {}
					if(params.conditionColumn) {
						params.conditionColumn += ';' + 'sfsh'
						params.conditionValue += ';' + '是'
					}else {
						params.conditionColumn = 'sfsh'
						params.conditionValue = '是'
					}
					this.$http({
						url: "pingjiafankui/group/pingjiajieguo",
						method: "get",
						params
					}).then(({data})=>{
						if (data && data.code === 0) {
							let res = data.data;
							let xAxis = [];
							let yAxis = [];
							let pArray = []
							for(let i=0;i<res.length;i++){
								if(this.boardBase&&i==this.boardBase.barNum){
									break;
								}
								// 统计图设置对了吗
								xAxis.push(res[i].pingjiajieguo);
								yAxis.push(parseFloat((res[i].total)));
								pArray.push({
									value: parseFloat((res[i].total)),
									name: res[i].pingjiajieguo
								})
							}
							var option = {};
							let titleObj = this.bar.title
							titleObj.text = '评价统计'
							
							const legendObj = this.bar.legend
							let tooltipObj = {trigger: 'item',formatter: '{b} : {c}'}
							tooltipObj = Object.assign(tooltipObj , this.bar.tooltip?this.bar.tooltip:{})
							let xAxisObj = this.bar.xAxis
							xAxisObj.type = 'value'
							
							let yAxisObj = this.bar.yAxis
							yAxisObj.type = 'category'
							yAxisObj.data = xAxis
							let seriesObj = {
								data: yAxis,
								type: 'bar',
							}
							seriesObj = Object.assign(seriesObj , this.bar.series)
							const gridObj = this.bar.grid
							option = {
								backgroundColor: this.bar.backgroundColor,
								color: this.bar.color,
								title: titleObj,
								legend: legendObj,
								grid: gridObj,
								tooltip: tooltipObj,
								xAxis: xAxisObj,
								yAxis: yAxisObj,
								series: [seriesObj]
							};
							// 使用刚指定的配置项和数据显示图表。
							pingjiajieguoChart1.setOption(option);
							  //根据窗口的大小变动图表
							window.onresize = function() {
								pingjiajieguoChart1.resize();
							};
						}
					})
				})
			},
